function removeCopyright($file) {
    $content = file_get_contents($file);
    // Define the copyright notice pattern you want to remove
    $copyrightPattern = '/\/\*\*(.*?)\*\*\//s'; // Matches PHP-style block comments that might contain a copyright notice
    // Remove the copyright notice
    $contentWithoutCopyright = preg_replace($copyrightPattern, '', $content);
    // Write the modified content back to the file
    file_put_contents($file, $contentWithoutCopyright);
}

// Specify the path to your PHP file
